CREATE TABLE IF NOT EXISTS users (id BIGSERIAL PRIMARY KEY, username VARCHAR(64) UNIQUE NOT NULL, display_name VARCHAR(128) NOT NULL, password_hash VARCHAR(256) NOT NULL, avatar_initials VARCHAR(4) NOT NULL DEFAULT 'XX', bio VARCHAR(256) DEFAULT '', phone VARCHAR(32) DEFAULT '', created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), last_seen_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), is_online BOOLEAN NOT NULL DEFAULT FALSE);